import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";

const BusMap = () => {
  const [buses, setBuses] = useState([]);
  const [runningCount, setRunningCount] = useState(0);
  const [ghostCount, setGhostCount] = useState(0);

  // Fetch buses every 5 seconds
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();

        setBuses(data);

        const running = data.filter((bus) => !bus.isGhost).length;
        const ghosts = data.filter((bus) => bus.isGhost).length;

        setRunningCount(running);
        setGhostCount(ghosts);
      } catch (error) {
        console.error("Error fetching buses:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      <MapContainer center={[40.7128, -74.006]} zoom={11} style={{ height: "100vh", width: "100%" }}>
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution='&copy; <a href="https://osm.org/copyright">OpenStreetMap</a> contributors'
        />

        {buses.map((bus, index) => (
          <CircleMarker
            key={index}
            center={[bus.lat, bus.lng]}
            radius={4} // smaller circle
            color={bus.isGhost ? "red" : "green"} // border color
            fillColor={bus.isGhost ? "red" : "green"} // inside fill
            fillOpacity={0.7} // slight transparency
            weight={1} // thin border
          >
            <Popup>
              <b>Bus ID:</b> {bus.id} <br />
              <b>Route:</b> {bus.route} <br />
              <b>Status:</b> {bus.isGhost ? "🚨 Ghost" : "✅ Running"}
            </Popup>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Legend */}
      <div
        style={{
          position: "absolute",
          bottom: "20px",
          left: "20px",
          background: "white",
          padding: "10px",
          borderRadius: "8px",
          boxShadow: "0 2px 5px rgba(0,0,0,0.3)",
        }}
      >
        <div>
          <span style={{ color: "green", fontWeight: "bold" }}>●</span> Running: {runningCount}
        </div>
        <div>
          <span style={{ color: "red", fontWeight: "bold" }}>●</span> Ghost: {ghostCount}
        </div>
      </div>
    </div>
  );
};

export default BusMap;
